import requests
import json
from requests.auth import HTTPBasicAuth

rabbitmq_api_url = 'http://localhost:15672/api'
rabbitmq_user = 'guest'
rabbitmq_password = 'guest'

vhosts = ['app1_vhost', 'app2_vhost']
users = [
    {'username': 'app1_user', 'password': 'password1', 'vhost': 'app1_vhost'},
    {'username': 'app2_user', 'password': 'password2', 'vhost': 'app2_vhost'}
]

def create_vhost(vhost):
    url = f'{rabbitmq_api_url}/vhosts/{vhost}'
    response = requests.put(url, auth=HTTPBasicAuth(rabbitmq_user, rabbitmq_password))
    print(f'Create vhost {vhost}: {response.status_code}')

def create_user(username, password):
    url = f'{rabbitmq_api_url}/users/{username}'
    data = {
        'password': password,
        'tags': ''
    }
    response = requests.put(url, auth=HTTPBasicAuth(rabbitmq_user, rabbitmq_password), data=json.dumps(data))
    print(f'Create user {username}: {response.status_code}')

def set_permissions(vhost, username):
    url = f'{rabbitmq_api_url}/permissions/{vhost}/{username}'
    data = {
        'configure': '.*',
        'write': '.*',
        'read': '.*'
    }
    response = requests.put(url, auth=HTTPBasicAuth(rabbitmq_user, rabbitmq_password), data=json.dumps(data))
    print(f'Set permissions for {username} on {vhost}: {response.status_code}')

for vhost in vhosts:
    create_vhost(vhost)

for user in users:
    create_user(user['username'], user['password'])
    set_permissions(user['vhost'], user['username'])